'[{"number":1,"title":"Load and inspect dataset","description":"Load your CSV and run initial inspection to understand shape, dtypes, and summary statistics.","code":"df = pd.read_csv(''data.csv'')\nprint(df.info())\nprint(df.describe())","language":"python"},{"number":2,"title":"Visualize missing data","description":"Generate a heatmap of missing values and a sorted count of nulls per column to prioritize imputation or dropping.","code":"sns.heatmap(df.isnull(), cbar=False)\ndf.isnull().sum().sort_values(ascending=False)","language":"python"},{"number":3,"title":"Distribution and correlation plots","description":"Plot histograms for all numeric columns and a horizontal bar chart of correlations with the target variable.","code":"df.hist(figsize=(15, 10))\ndf.select_dtypes(''number'').corrwith(df[''target'']).sort_values().plot.barh()","language":"python"},{"number":4,"title":"Outlier detection with IQR","description":"Identify outlier rows using the interquartile range method across all numeric columns.","code":"Q1 = df.quantile(0.25)\nQ3 = df.quantile(0.75)\nIQR = Q3 - Q1\noutliers = df[((df < Q1 - 1.5 * IQR) | (df > Q3 + 1.5 * IQR)).any(axis=1)]","language":"python"}]'::jsonb,
NULL,NULL,780,0,0,false,true,false,NULL,true);

