99900,900,false,
'[{"number":1,"title":"Define cohorts by signup week","description":"Group users into cohorts based on their signup week or month so each cohort represents a homogeneous group of users who started at the same time."},{"number":2,"title":"Core cohort SQL with CTEs","description":"Build the foundational SQL using CTEs for cohort assignment and activity tracking across weeks.","code":"WITH cohorts AS (\n  SELECT user_id, date_trunc(''week'', created_at) AS cohort_week\n  FROM users\n),\nactivity AS (\n  SELECT user_id, date_trunc(''week'', event_at) AS activity_week\n  FROM events\n)","language":"sql"},{"number":3,"title":"Calculate weeks since signup and retention rate","description":"Join cohorts with activity, calculate weeks elapsed since the cohort week, and compute the retention percentage for each week bucket per cohort."},{"number":4,"title":"Output cohort retention table","description":"Receive a formatted cohort table showing week-0 through week-12 retention percentages for each cohort, ready to paste into a spreadsheet or BI tool."}]'::jsonb,
