'funnel-analysis-sql','Funnel Analysis SQL','Build multi-step conversion funnels in PostgreSQL or BigQuery','Build multi-step conversion funnel queries in PostgreSQL or BigQuery using window functions, calculate step-by-step drop-off, and segment by acquisition channel.',
'data-analytics',NULL,ARRAY['funnel','sql','analytics'],'intermediate',
99900,900,false,
'[{"number":1,"title":"Define funnel steps","description":"Define your funnel steps in sequence, for example: visit, signup, activate, and purchase — each mapped to a specific event name in your events table."},{"number":2,"title":"SQL with window functions","description":"Build the funnel query using conditional aggregation to flag each step completion per user.","code":"SELECT\n  user_id,\n  MAX(CASE WHEN event = ''visit'' THEN 1 END) AS step1,\n  MAX(CASE WHEN event = ''signup'' THEN 1 END) AS step2,\n  MAX(CASE WHEN event = ''activate'' THEN 1 END) AS step3,\n  MAX(CASE WHEN event = ''purchase'' THEN 1 END) AS step4\nFROM events\nGROUP BY user_id","language":"sql"},{"number":3,"title":"Calculate drop-off between steps","description":"Wrap the base query to calculate the absolute and percentage drop-off between each consecutive funnel step."},{"number":4,"title":"Segment by acquisition channel","description":"Add acquisition channel segmentation to identify which traffic sources have the highest conversion rates through your funnel."}]'::jsonb,
NULL,NULL,720,0,0,false,true,false,NULL,true);

